      "keystrokes": "cat > /app/task_file/scripts/verify.py <<'PY'
import json, sys
from pathlib import Path
sys.path.insert(0, str(Path(__file__).resolve().parent))
from cost_model import CostModel

def load(path):
    return [json.loads(l) for l in open(path)]

thresholds = {
    '1': {'cost': 3.0e11, 'pad_ratio': 0.055, 'p95_latency_ms': 2.1e6, 'sequential_timecost': 2.7e8},
    '2': {'cost': 4.8e10, 'pad_ratio': 0.15, 'p95_latency_ms': 2.1e5, 'sequential_timecost': 3.2e7},
}

all_shapes = set()
plans = {}
for b in ['1','2']:
    reqs_list = load(f'/app/task_file/input_data/requests_bucket_{b}.jsonl')
    plan = load(f'/app/task_file/output_data/plan_b{b}.jsonl')
    plans[b] = plan
    reqs = {r['request_id']: r for r in reqs_list}
    ids = set(r['request_id'] for r in plan)
    bucket_shapes = set((r['shape']['seq_align'], r['shape']['heads_align'], r['shape']['hidden_align']) for r in plan)
    all_shapes.update(bucket_shapes)
    print(f'bucket {b}: records={len(plan)} unique_ids={len(ids)} missing={len(reqs)-len(ids)} duplicates={len(plan)-len(ids)} batches={len(set(r["batch_id"] for r in plan))} shapes_in_bucket={len(bucket_shapes)}')
    cm = CostModel(64)
    totals = cm.plan_metrics(reqs, plan)
    th = thresholds[b]
    for k in ['cost','pad_ratio','p95_latency_ms','sequential_timecost']:
        print(f'  {k}: {totals[k]:.6e} threshold {th[k]:.6e} {"PASS" if totals[k] < th[k] else "FAIL"}')

print(f'global_shapes: {len(all_shapes)} / 8')
print(f'shape_list: {sorted(all_shapes)}')
if len(all_shapes) > 8:
    print('GLOBAL SHAPE LIMIT FAILED')
    sys.exit(1)
PY
